--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -4150,6 +4150,28 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
     }
   }

+  // For umul.with.overflow, handle:
+  // Overflow | (x * C1) ugt C2  -->  x ugt C2 / C1
+  // Since overflow implies x*C1 >= 2^N > C2, the overflow flag is redundant.
+  const WithOverflowInst *WOMul;
+  const Value *WOVMul;
+  const APInt *C1Mul, *C2Mul;
+  Value *OvMul;
+  CmpPredicate PredMul;
+  if (match(&I, m_c_Or(m_CombineAnd(m_ExtractValue<1>(m_CombineAnd(
+                                        m_WithOverflowInst(WOMul), m_Value(WOVMul))),
+                                    m_Value(OvMul)),
+                       m_OneUse(m_ICmp(PredMul, m_ExtractValue<0>(m_Deferred(WOVMul)),
+                                       m_APInt(C2Mul))))) &&
+      WOMul->getBinaryOp() == Instruction::Mul && !WOMul->isSigned() &&
+      PredMul == ICmpInst::ICMP_UGT &&
+      match(WOMul->getRHS(), m_APInt(C1Mul)) && !C1Mul->isZero()) {
+    APInt NewC = C2Mul->udiv(*C1Mul);
+    Value *NewCmp = Builder.CreateICmpUGT(WOMul->getLHS(),
+        ConstantInt::get(WOMul->getLHS()->getType(), NewC));
+    return replaceInstUsesWith(I, NewCmp);
+  }
+
   // (~x) | y  -->  ~(x & (~y))  iff that gets rid of inversions
   if (sinkNotIntoOtherHandOfLogicalOp(I))
     return &I;

